const titleCase = (value) =>
  value
    .split("_")
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(" ");

const normalizeKey = (value) =>
  String(value || "")
    .toLowerCase()
    .replace(/ç/g, "c")
    .replace(/ğ/g, "g")
    .replace(/ı/g, "i")
    .replace(/ö/g, "o")
    .replace(/ş/g, "s")
    .replace(/ü/g, "u")
    .replace(/[^a-z0-9]+/g, "")
    .trim();

const TURKEY_CITY_OPTIONS = TURKEY_CITIES_81;

const TURKEY_DISTRICT_HINTS = Object.entries(TURKEY_DISTRICTS_BY_CITY).reduce((acc, [city, districts]) => {
  const key = normalizeKey(city);
  const values = Array.from(
    new Set(
      (Array.isArray(districts) ? districts : [])
        .map((item) => String(item || "").trim())
        .filter(Boolean)
    )
  );
  if (key) acc[key] = values;
  return acc;
}, {});

const dedupeLocationLabels = (items = []) => {
  const seen = new Set();
  const out = [];
  for (const raw of items) {
    const value = String(raw || "").trim();
    if (!value) continue;
    const key = normalizeKey(value);
    if (!key || seen.has(key)) continue;
    seen.add(key);
    out.push(value);
  }
  return out;
};

