const TURKISH_FIX_HINT = /turkce|hazir|once|sec|gorsel|goruntu|baglanti|yukle|kilavuz|ozellik|sifir|henuz|tum|coklu|dusuk|yuksek|ruzgar|isik|islak|acik|agirlik|hastalik|saglik|sehir|ilce|urun|uret|ciftci|gubre|ilac|teshis|yagis|gunes|buyuksehir|toprag|ozet|oneri|uyari|yonet|donus|gorun/i;
const TURKISH_FIX_ATTRS = ["placeholder", "title", "aria-label", "alt"];

const applyTurkishCase = (replacement, source) => {
  if (!source) return replacement;
  if (source === source.toUpperCase()) return replacement.toLocaleUpperCase("tr-TR");
  if (source[0] === source[0].toUpperCase()) {
    const [head, ...rest] = replacement;
    return `${head.toLocaleUpperCase("tr-TR")}${rest.join("")}`;
  }
  return replacement;
};

const normalizeTurkishText = (value) => {
  if (typeof value !== "string" || !value || !TURKISH_FIX_HINT.test(value)) return value;
  let next = value;
  TURKISH_WORD_FIXES.forEach(([asciiWord, trWord]) => {
    const re = new RegExp(`\\b${asciiWord}\\b`, "gi");
    next = next.replace(re, (match) => applyTurkishCase(trWord, match));
  });
  return next;
};

const normalizeTurkishDom = (root) => {
  if (!root) return;
  const walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT);
  let node = walker.nextNode();
  while (node) {
    const original = node.nodeValue || "";
    const normalized = normalizeTurkishText(original);
    if (normalized !== original) node.nodeValue = normalized;
    node = walker.nextNode();
  }
  const all = root.querySelectorAll("*");
  all.forEach((el) => {
    TURKISH_FIX_ATTRS.forEach((attr) => {
      const raw = el.getAttribute(attr);
      if (!raw) return;
      const normalized = normalizeTurkishText(raw);
      if (normalized !== raw) el.setAttribute(attr, normalized);
    });
  });
};

